INSERT INTO public.code_sections (id, chapitre_id, numero, titre, created_at, updated_at, contenu) VALUES ('1625c22e-fc56-4530-b113-8f3e846e180f', '6cc3b5c0-f505-42f2-a746-1a5bb2869187', 1, 'Avantages particuliers accordés durant la phase de réalisation des investissements', '2026-05-20 09:18:11.01854+00', '2026-05-20 09:18:11.01854+00', NULL);
INSERT INTO public.code_sections (id, chapitre_id, numero, titre, created_at, updated_at, contenu) VALUES ('d55cbd69-9862-4ab0-ae82-e584e217fb62', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', 1, 'Régime des investissements stratégiques', '2026-05-20 09:19:32.6129+00', '2026-05-20 09:19:32.6129+00', NULL);
INSERT INTO public.code_sections (id, chapitre_id, numero, titre, created_at, updated_at, contenu) VALUES ('4267e79e-2454-4b6f-bba2-00d06a55fa98', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', 2, 'Régime de l''investissement socialement responsable', '2026-05-20 09:20:08.938636+00', '2026-05-20 09:20:08.938636+00', NULL);
INSERT INTO public.code_sections (id, chapitre_id, numero, titre, created_at, updated_at, contenu) VALUES ('0c309c38-3820-46c7-9002-3ed351b928f3', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', 3, 'Avantages fiscaux et douaniers propres aux régimes particuliers d''investissement', '2026-05-20 09:21:11.362668+00', '2026-05-20 09:21:11.362668+00', NULL);
INSERT INTO public.code_sections (id, chapitre_id, numero, titre, created_at, updated_at, contenu) VALUES ('3f39b3d8-c7bd-41c3-999c-991ee161deb0', '6cc3b5c0-f505-42f2-a746-1a5bb2869187', 2, 'Avantages accordés pendant la phase d''exploitation', '2026-05-20 09:18:49.66082+00', '2026-05-20 09:18:49.66082+00', 'La phase d''exploitation débute à partir de la date de notification par l''investisseur de la première opération d''exploitation ou de production, marquant le démarrage des activités. Après cette notification, il est immédiatement délivré à l''investisseur un agrément pour la phase d''exploitation reprenant les avantages octroyés.');
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('54913c33-665e-4d03-9d12-59d2bda47445', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', 'd55cbd69-9862-4ab0-ae82-e584e217fb62', 37, 'Éligibilité au régime des investissements stratégiques', 'Les investissements obéissant aux critères prévus par le présent article peuvent bénéficier du régime des investissements stratégiques.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('0d477f84-6544-46c4-b848-d5f56d6640bb', '3afbc0a2-4148-4772-b61e-257799826ed6', NULL, 3, 'Définitions', 'Au sens du présent Code, on entend par :&nbsp;<div><ul class="dash-list"><li><b>agrément</b> : acte délivré par le Ministre chargé des Finances qui établit que l''investisseur est agréé au Code des investissements et bénéficie de tout ou partie des avantages prévus par ce Code. Il peut être accordé pour la phase de réalisation des investissements et pour la phase d''exploitation ou de production, dans les conditions déterminées par le présent Code ;</li><li><b>agrément d''extension</b> : agrément délivré pour un investissement initié par une entreprise ayant déjà bénéficié d''un ou de plusieurs agréments, en vue de :</li><ul><li><span style="font-family: &quot;Google Sans&quot;;">l''achèvement des travaux d''investissement, sous réserve du non-démarrage de l''exploitation et de la production de justificatifs qui attestent objectivement le non bouclage des investissements dans les délais impartis ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;">l''augmentation de la capacité de production globale ou de la valeur d''acquisition des actifs immobilisés à hauteur de 25% ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;">la rénovation ou de l''acquisition de composantes industrielles pour les seuils et les secteurs d''activité définis par arrêté du Ministre chargé des Finances ;</span></li></ul><li><span style="font-family: &quot;Google Sans&quot;;"><b>comité d''agrément de l''économie sociale et solidaire (CAESS)&nbsp;</b>: comité prévu par décret et institué par arrêté, en application de la loi d''orientation relative à l''Economie sociale et solidaire ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>comité technique chargé du suivi des investissements (CTSI)</b> : comité en charge du contrôle du respect par les investisseurs et leurs investissements des exigences légales prévues par le présent Code ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>contenu local</b> : ensemble des initiatives prises en vue de promouvoir l''utilisation des biens et des services nationaux, ainsi que le développement de la participation de la main-d''œuvre, de la technologie et du capital nationaux dans les activités des investisseurs dans les secteurs de la vie économique ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>contrôle de conformité</b> : vérification par les services étatiques compétents du respect par l''investisseur des lois et règlements, des procédures, des engagements et obligations liés à l''agrément et à l''investissement ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>enregistrement</b> : formalité consistant pour un investisseur à saisir l''organe en charge de la promotion des investissements aux fins d''enregistrement au répertoire des investisseurs et qui donne lieu à la remise d''un récépissé ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>entreprise</b> : unité de production ou de transformation de biens et services, quelle que soit sa forme juridique, qu''il s''agisse d''une entreprise individuelle ou d''une personne morale ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>investissement</b> : dépense faite par un investisseur afin de se doter ou de développer une capacité de production de biens et/ou de services, de sorte à maintenir une activité substantielle sur le territoire national, en conformité avec les lois et règlements ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>investisseur</b> : personne physique ou morale de nationalité sénégalaise ou étrangère réalisant, dans les conditions définies par le présent Code, des opérations d''investissements sur le territoire sénégalais ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>investissement stratégique</b> : investissement portant sur des secteurs d''activités clés prévues par le présent Code ou dans les instruments de politiques publiques en vigueur, et qui peut donner lieu à un agrément délivré par le Ministre chargé des Finances ou à une convention signée entre le Ministre chargé des Finances et l''investisseur ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>investissement socialement responsable (ISR)</b> : investissement qui s''inscrit, dans le cadre de son exécution, dans une démarche de participation au développement communautaire et territorial, dans le respect des principes de durabilité, d''équité et d''inclusion sociale ;</span></li><li><span style="font-family: &quot;Google Sans&quot;;"><b>législation du travail</b> : ensemble des textes législatifs et réglementaires ainsi que des dispositions des conventions collectives applicables le cas échéant, et fixant les règles juridiques régissant les relations entre employeurs et travailleurs ;
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('be2f1c9c-510c-4a6a-b331-fad8c7598f0f', 'da7d3934-f41e-488a-b9af-9ae014deba42', NULL, 54, 'Abrogation', 'La présente loi abroge et remplace la loi n° 2004-06 du 6 février 2004 portant Code des Investissements et toutes autres dispositions antérieures contraires.', '2026-05-20 09:53:10.473161+00', '2026-05-20 09:53:10.473161+00');
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('489c67ed-7b6d-44ee-83df-be440d0eee59', '3afbc0a2-4148-4772-b61e-257799826ed6', NULL, 4, 'Traités et accords conclus avec des Etats ou des organisations', 'Les dispositions du présent Code ne font pas obstacle aux avantages et garanties qui sont prévus par les traités ou accords conclus ou pouvant être conclus entre le Sénégal et d’autres Etats ou d’autres organisations.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('dd16165a-1e08-4d52-a88a-3ffa35429c8d', '553f7aaf-e9c6-4539-8a0d-958bfba0287c', NULL, 7, 'Droits et libertés fondamentaux', 'Les lois et règlements en vigueur garantissent la liberté d''entreprendre ainsi que le droit à la propriété privée à toutes les personnes physiques ou morales résidant, même temporairement, sur le territoire national, sans distinction de nationalité.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('9cceeac5-38b8-4317-8388-bc96d54c531c', '553f7aaf-e9c6-4539-8a0d-958bfba0287c', NULL, 12, 'Garantie de convertibilité et d''accès aux devises', 'Sous réserve du respect de la réglementation communautaire en vigueur, il est garanti à tout investisseur la libre convertibilité du Franc CFA.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('60b68c7a-a2f1-4b26-bf0b-79c15fd766e9', '91e73fbc-e6fa-44bb-970e-7cb2c97f195a', NULL, 16, 'Conformité avec le droit national et international', 'Les investisseurs réalisent et mènent leurs opérations d''investissement dans le respect des lois et règlements en vigueur au Sénégal, du droit communautaire ainsi que du droit international applicables.', '2026-05-20 09:30:35.838441+00', '2026-05-20 09:30:35.838441+00');
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('409b8b4f-140e-49ea-a848-8af3cc1d4e63', '92baa576-4c13-4bf1-8f94-6292c8896cad', NULL, 23, 'Retrait de l''agrément', 'Le manquement par l''investisseur à tout ou partie de ses obligations peut entrainer la suspension des avantages particuliers dont il a bénéficié, puis le retrait de l''agrément, dans les conditions prévues par le présent Code.', '2026-05-20 09:33:04.434678+00', '2026-05-20 09:33:04.434678+00');
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('520afd68-4dc3-498d-872b-8745b23ff8e5', '78566a2d-bdc7-4f6f-954b-9e04c91a06f4', '07a09545-ca2d-4c4a-9a7c-3e49998e72b4', 24, 'Accès au financement pour la formation du personnel', 'Les entreprises enregistrées au répertoire des investisseurs peuvent bénéficier d''un appui à la formation initiale ainsi qu''aux actions de formation continue de leur personnel.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('3209aeb0-97ca-4971-9046-bd4d6397df05', '78566a2d-bdc7-4f6f-954b-9e04c91a06f4', '10c44003-da66-472f-ac13-e727e7bd9017', 27, 'Accompagnement pour l''obtention des titres d''entrée et de séjour', 'L''organe en charge de la promotion des investissements prend toutes les mesures pour faciliter la délivrance à l''investisseur des visas d''entrée et de séjour au Sénégal, en rapport notamment avec les services compétents du Ministère en charge de l''Intérieur et du Ministère en charge des Affaires étrangères.', '2026-05-20 09:34:59.334732+00', '2026-05-20 09:34:59.334732+00');
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('18324ee1-dda0-47b6-ade7-940691344063', '78566a2d-bdc7-4f6f-954b-9e04c91a06f4', '10c44003-da66-472f-ac13-e727e7bd9017', 30, 'Création de zones aménagées pour l''investissement (ZAI)', 'L''État, les collectivités territoriales ou les partenaires privés peuvent créer des zones aménagées pour investissement.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('8981636a-bb28-4201-af2d-15b82ac56dc1', '6cc3b5c0-f505-42f2-a746-1a5bb2869187', '3f39b3d8-c7bd-41c3-999c-991ee161deb0', 36, 'Avantages fiscaux', 'Pendant la phase d''exploitation, l''investisseur bénéficie d''un crédit d''impôt pour investissement.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('abac5e33-d2a2-4e16-8b1d-6abf10e0cbae', 'da7d3934-f41e-488a-b9af-9ae014deba42', NULL, 53, 'Modalités d''application de la loi', 'Les modalités d''application du présent Code sont fixées par voie règlementaire.', '2026-05-20 09:51:22.003901+00', '2026-05-20 09:51:22.003901+00');
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('135a408f-bd78-4016-96e9-1a9498e7d876', '9b37bfc3-4153-4d47-8fae-7aa7dcc3014b', NULL, 50, 'Prévention des différends', 'L''organe en charge de la promotion des investissements et le CSTI mettent en œuvre, chacun en ce qui le concerne, les actions nécessaires à la prévention des différends, notamment en recevant les griefs des investisseurs susceptibles de générer des conflits entre ces derniers et les administrations publiques.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('fbad5b21-ae93-4412-9343-4291121aef5d', 'a85e7396-4141-4f3e-8de6-78e9263fed67', NULL, 47, 'Comité technique de suivi des investissements', 'Le Comité technique de suivi des investissements (CTSI) est mis en place sous l''autorité du Ministre chargé des Finances.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('16a059fa-571f-4993-a829-36b8a1ec8802', '3afbc0a2-4148-4772-b61e-257799826ed6', NULL, 1, 'Objet', 'La présente loi fixe les règles qui régissent la promotion, la facilitation et la protection de l’investissement privé pour favoriser le développement économique, social et durable au Sénégal.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('0a7372cc-c1bb-4640-8fa7-0d23c58649f6', '3afbc0a2-4148-4772-b61e-257799826ed6', NULL, 5, 'Droit de réglementer', 'L’Etat a le droit de réglementer, notamment de prendre des mesures pour faire en sorte que les investissements sur son territoire soient compatibles avec les objectifs et les principes du développement durable, ainsi qu’avec d’autres objectifs légitimes de politique économique, sociale, environnementale et sanitaire, outre les intérêts essentiels de sécurité.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('da657ec8-5945-44ef-9631-122a9b3c5962', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', '4267e79e-2454-4b6f-bba2-00d06a55fa98', 42, 'Condition d''obtention de l''agrément d''investissement socialement responsable', 'Tout investisseur qui le souhaite peut obtenir l''agrément d''investissement socialement responsable sous réserve de s''engager auprès de la collectivité territoriale de son lieu d''implantation à réaliser des investissements à caractère économique et social au bénéfice des populations et dans le cadre des principes de durabilité, d''équité et d''inclusion sociale.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('f5a456d3-e310-46b8-9993-e84533f0e4d9', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', 'd55cbd69-9862-4ab0-ae82-e584e217fb62', 40, 'Obligations liées au bénéfice du régime des investissements stratégiques', 'Tout investisseur bénéficiaire du régime des investissements stratégiques prévu par le présent Code est tenu de satisfaire aux obligations suivantes :
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('a4d95012-61fd-446f-a4a7-dfa9e396b5bd', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', 'd55cbd69-9862-4ab0-ae82-e584e217fb62', 38, 'Agrément au régime des investissements stratégiques', 'Pour obtenir l''agrément au régime des investissements stratégiques, l''investisseur adresse au Ministre chargé des Finances par l''entremise de l''organe en charge de la promotion des investissements, une demande accompagnée d''un programme d''investissement. L''octroi de l''agrément est matérialisé par la signature d''une convention entre le Ministre chargé des Finances et l''investisseur porteur du projet.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('868a097b-41c8-4f82-bf16-f00d66ab93cb', '553f7aaf-e9c6-4539-8a0d-958bfba0287c', NULL, 6, 'Egalité de traitement', 'Il est garanti une égalité de traitement entre l''investisseur national et l''investisseur étranger dans des circonstances analogues.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('add30b70-2b58-4450-9846-27398334db20', '553f7aaf-e9c6-4539-8a0d-958bfba0287c', NULL, 8, 'Traitement administratif et judiciaire', 'L''Etat garantit que les investissements et les investisseurs ne fassent pas l''objet d''un traitement qui constituerait, à titre exclusif, un déni manifeste ou un traitement abusif dans les procédures administratives ou judiciaires.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('10a19ec3-a224-4eb4-b12d-e6060da62888', '553f7aaf-e9c6-4539-8a0d-958bfba0287c', NULL, 9, 'Libertés spécifiques de l''investisseur', 'Sous réserve du respect des lois et règlements en vigueur, l''investisseur jouit sur le territoire national d''une pleine et entière liberté, notamment pour :
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('a515eea9-e92f-4cac-9488-51723f0acd70', '553f7aaf-e9c6-4539-8a0d-958bfba0287c', NULL, 10, 'Garantie contre les mesures alinéatrices de la propriété', 'Il est garanti à l''investisseur la protection contre toute mesure de nationalisation ou d''expropriation, directement ou indirectement, sauf pour cause d''utilité publique et sous réserve du respect des procédures prévues par les textes en vigueur et moyennant une juste et préalable indemnité compensatrice.', '2026-05-20 09:28:15.812608+00', '2026-05-20 09:28:15.812608+00');
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('8e5d6dad-4370-435f-a330-4f95ccf7f0ad', '553f7aaf-e9c6-4539-8a0d-958bfba0287c', NULL, 11, 'Garantie de transfert de capitaux à l''étranger', 'Il est garanti à l''investisseur étranger la liberté de transférer dans son pays d''origine ou tout autre pays de son choix, les revenus, dividendes et produits de toute nature résultant de son exploitation, dans les conditions prévues par la réglementation des relations financières extérieures des Etats membres de l''Union économique et monétaire ouest-africaine (UEMOA).
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('1923d5f7-ce46-4a4c-b13f-5dc19d1af425', '553f7aaf-e9c6-4539-8a0d-958bfba0287c', NULL, 13, 'Garanties d''accès aux matières premières', 'L''investisseur a libre accès aux matières premières de toutes natures produites au Sénégal, sauf cas de motif impérieux d''intérêt public entraînant une mesure générale de restriction, non fondée sur la nationalité.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('1e579a41-e6e8-409e-97c9-858b6ffb203a', '91e73fbc-e6fa-44bb-970e-7cb2c97f195a', NULL, 14, 'Engagements de l''investisseur titulaire d''un agrément', 'Outre les autres obligations générales prévues par le présent Code, tout investisseur bénéficiaire d''un agrément au présent Code est tenu de satisfaire aux obligations suivantes :
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('9497da92-d387-4da5-9f43-00eaf5acdb83', '91e73fbc-e6fa-44bb-970e-7cb2c97f195a', NULL, 15, 'Enregistrement de l''investissement', 'Tout investissement supérieur ou égal à quinze (15) millions de francs CFA est enregistré auprès de l''organe en charge de la promotion des investissements en indiquant le nom et le siège de l''entreprise, le montant de l''investissement, la structure du capital et le nombre d''emplois à créer. Ces informations sont enregistrées dans le répertoire des investisseurs tenu par ledit organe et mises à jour chaque année.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('02177939-9546-4be5-8fbe-f75d3680e8b5', '91e73fbc-e6fa-44bb-970e-7cb2c97f195a', NULL, 17, 'Protection de l''environnement', 'L''investisseur est solidaire avec son investissement et s''engage à répondre pleinement de toute obligation préventive et de toute conséquence découlant dudit investissement sur l''environnement.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('f04f256c-50aa-4e68-adcb-5f937fb176db', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', 'd55cbd69-9862-4ab0-ae82-e584e217fb62', 41, 'Obligations liées à l''arrêt des activités et au non-respect des engagements', 'Toute entreprise ayant bénéficié du régime des investissements stratégiques, qui cesse d''exercer ses activités pendant une période de six (06) mois ou à la fin de la phase d''investissement, sera tenue de rembourser les montants des impôts non acquittés du fait de ce régime, si la cessation des activités résulte de manœuvres frauduleuses, sans préjudice des éventuelles poursuites judiciaires encourues. Il en va de même si avant la fin de la phase d''investissement, les manœuvres frauduleuses sont constatées par les services compétents.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('c0a07387-63f0-42b1-8808-c395de4837a4', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', 'd55cbd69-9862-4ab0-ae82-e584e217fb62', 39, 'Obligations liées à la demande du régime des investissements stratégiques', 'Les personnes physiques ou morales qui sollicitent le bénéfice du régime des investissements stratégiques s''obligent à :
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('36e07c4f-f08b-4153-a31b-667bf7c925a9', '91e73fbc-e6fa-44bb-970e-7cb2c97f195a', NULL, 18, 'Ethique des affaires et normes du travail', 'L''investisseur s''engage à se conformer aux normes les plus élevées en matière d''éthique des affaires et de normes du travail, en particulier :
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('dd521866-fb90-4044-963c-6f18af3dbc56', '91e73fbc-e6fa-44bb-970e-7cb2c97f195a', NULL, 19, 'Responsabilité sociétale des entreprises', 'L''investisseur est responsable de toute conséquence résultant de son investissement.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('0149aa11-62a1-47b2-81ca-1c9019ae3ea7', '92baa576-4c13-4bf1-8f94-6292c8896cad', NULL, 20, 'L''instruction des dossiers liés au Code des investissements', '**→ Dossier de demande d''agrément**
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('4f75eee5-6e9f-42c5-b173-02858ecd8c0c', '92baa576-4c13-4bf1-8f94-6292c8896cad', NULL, 21, 'Délivrance de l''agrément et des listes', 'Il est délivré à l''investisseur un agrément pour la phase de réalisation des investissements.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('4b11242f-6fc3-47d8-8b3a-43983de83832', '92baa576-4c13-4bf1-8f94-6292c8896cad', NULL, 22, 'Durée de l''agrément et des listes', 'La durée du premier agrément accordé à une entreprise nouvelle ou déjà existante est de trois (03) ans, à compter de la date de signature, pour les investissements à réaliser dans les régions de Dakar et Thiès. Cette durée peut être portée à cinq (05) ans lorsque les investissements sont réalisés dans les régions autres que Dakar et Thiès.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('5f20efba-23a1-4704-ba0c-b95486633ee1', '78566a2d-bdc7-4f6f-954b-9e04c91a06f4', '07a09545-ca2d-4c4a-9a7c-3e49998e72b4', 25, 'Avantages sociaux', 'A compter de la date d''octroi de l''agrément pour la phase d''exploitation, les travailleurs recrutés par les entreprises agréées sont assimilés aux travailleurs engagés en complément d''effectif pour exécuter des travaux nés d''un surcroît d''activités au sens de la législation du travail.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('ce9d3ef8-3411-46cf-9eca-2530451a42e4', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', '0c309c38-3820-46c7-9002-3ed351b928f3', 45, 'Champ des avantages', 'Les investisseurs agréés aux régimes particuliers d''investissement définis par le présent Code bénéficient :
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('95005d09-d1f9-4a20-bd65-feacb6f20ca7', '78566a2d-bdc7-4f6f-954b-9e04c91a06f4', '10c44003-da66-472f-ac13-e727e7bd9017', 26, 'Démarches administratives', 'Tout investisseur peut, pour toute procédure administrative devant être réalisée auprès d''un service de l''Etat, d''une collectivité territoriale ou d''un établissement public, dans le cadre d''un projet d''investissement, saisir l''organe en charge de la promotion des investissements pour bénéficier de son accompagnement en vue de l''accomplissement des formalités nécessaires à la réalisation de son projet d''investissement.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('8d48c578-225d-4936-b16a-f399882ce8e3', '78566a2d-bdc7-4f6f-954b-9e04c91a06f4', '10c44003-da66-472f-ac13-e727e7bd9017', 28, 'Accès au foncier', 'Tout investisseur est libre, conformément aux textes législatifs et réglementaires en vigueur, d''acquérir les droits de propriété foncière nécessaires à l''exercice de tout ou partie des activités de son entreprise auprès de personnes publiques ou privées possédant des droits de propriété ou tout autre droit réel immobilier.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('90f66330-1dd6-4f07-8927-a9ccf2d57f21', '6cc3b5c0-f505-42f2-a746-1a5bb2869187', '1625c22e-fc56-4530-b113-8f3e846e180f', 32, 'Durée de la phase d''investissement', 'La durée de la phase de réalisation des investissements est de trois (03) ans pour les investissements à réaliser dans les régions de Dakar et Thiès.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('9cf8156a-972b-4aae-81d5-1d57585c83c5', '6cc3b5c0-f505-42f2-a746-1a5bb2869187', '1625c22e-fc56-4530-b113-8f3e846e180f', 34, 'Nature et portée des avantages fiscaux et douaniers', 'Pendant la période de réalisation des investissements et dans les conditions prévues respectivement par le Code général des Impôts et le Code des Douanes, il est accordé à l''investisseur les avantages fiscaux et douaniers ci-après :
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('673556ff-2c18-44f6-9cf8-fb287c7173a7', '3afbc0a2-4148-4772-b61e-257799826ed6', NULL, 2, 'Champ d''application', 'La présente loi régit les investissements privés sur toute l’étendue du territoire national, qu’ils soient domestiques ou étrangers, sous réserve des dispositions prévues pour des secteurs d’activités spécifiques ou des régimes particuliers.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('8a0ece5b-5390-4a09-893c-588a6371a7fb', '78566a2d-bdc7-4f6f-954b-9e04c91a06f4', '10c44003-da66-472f-ac13-e727e7bd9017', 29, 'Accès aux zones économiques spéciales (ZES)', 'Il est ouvert la possibilité pour tout investisseur remplissant les conditions légales et règlementaires prévues à cet effet, de solliciter l''organe en charge de la promotion des investissements pour s''installer dans une zone économique spéciale (ZES).
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('79548503-902a-4eb7-b719-506b2f320653', '78566a2d-bdc7-4f6f-954b-9e04c91a06f4', '10c44003-da66-472f-ac13-e727e7bd9017', 31, 'Digitalisation des procédures administratives liées à l''investissement', 'Il est mis en place une plateforme numérique, dont la gestion est confiée à l''organe en charge de la promotion des investissements.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('86a36c49-61c8-4d70-81c6-751c9add29f7', '6cc3b5c0-f505-42f2-a746-1a5bb2869187', '1625c22e-fc56-4530-b113-8f3e846e180f', 33, 'Éligibilité au régime fiscal incitatif de droit commun', 'Toute petite et moyenne entreprise porteuse d''un projet d''investissement d''un montant supérieur ou égal à quinze (15) millions de francs CFA, qui s''engage à réaliser cet investissement dans un secteur défini et sur une durée d''exécution n''excédant pas trois (03) ans ou cinq (05) ans selon la région d''implantation du projet, est éligible au régime fiscal incitatif de droit commun, suivant les conditions déterminées par le Code général des Impôts.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('c32baeb5-bf9c-4f38-8afe-4988e285ea71', '6cc3b5c0-f505-42f2-a746-1a5bb2869187', '1625c22e-fc56-4530-b113-8f3e846e180f', 35, 'Stabilité des avantages fiscaux et douaniers', 'Il est garanti à l''investisseur que les incitations fiscales et douanières octroyées dans le cadre d''un agrément au présent Code ne seront pas modifiées pendant une période de trois (03) ans ou de cinq (05) ans selon le type d''agrément, à compter de la date de sa signature.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('459d216f-7134-4fc9-9134-762026a3a50d', 'da7d3934-f41e-488a-b9af-9ae014deba42', NULL, 52, 'Situation des entreprises titulaires d''agréments délivrés sous le régime antérieur', 'Les agréments accordés avant l''entrée en vigueur du présent Code restent applicables jusqu''à leur terme ou la notification de démarrage de l''exploitation. Les entreprises titulaires desdits agréments peuvent également être admises, sur leur demande, au bénéfice du présent Code dans la mesure où elles remplissent les conditions fixées.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('3126d5b4-6186-4481-a47f-55ac2c01cde8', '9b37bfc3-4153-4d47-8fae-7aa7dcc3014b', NULL, 51, 'Règlement des différends', 'Tout différend entre l''Etat et un investisseur en relation avec son investissement et résultant de l''interprétation ou de l''application du présent Code est préalablement soumis à un règlement à l''amiable, tel que la négociation, les bons offices, la médiation ou la conciliation.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('e9927a49-49c8-4ae1-9531-700e73ea56b4', 'a85e7396-4141-4f3e-8de6-78e9263fed67', NULL, 49, 'Sanctions pour non-respect des conditions d''agrément', 'Le manquement par l''investisseur à tout ou partie des obligations qui lui incombent en vertu du présent Code, peut entraîner le retrait de l''agrément. Ce retrait est précédé d''un délai de grâce de trois (03) mois au maximum, au cours duquel l''investisseur est invité à régulariser sa situation. Pendant cette période de grâce, les avantages fiscaux et douaniers liés à l''agrément sont suspendus.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('2004f911-8e89-4a35-be04-f9440ec676c7', 'a85e7396-4141-4f3e-8de6-78e9263fed67', NULL, 48, 'Contrôle de conformité', 'Il pèse sur tout investisseur bénéficiant des avantages fiscaux et douaniers prévus par la présente loi une obligation de se soumettre au contrôle de conformité. L''investisseur doit fournir à l''organe en charge de la promotion des investissements et au ministère en charge des Finances, dans les quatre-vingt-dix (90) jours suivant la clôture de l''exercice fiscal, des informations précises permettant de vérifier l''effectivité de l''investissement agréé.', '2026-05-20 09:49:22.772188+00', '2026-05-20 09:49:22.772188+00');
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('37d0a9b9-fe3a-4be1-ace7-226e63e28430', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', '0c309c38-3820-46c7-9002-3ed351b928f3', 46, 'Modalités d''octroi des avantages', 'Les types d''avantages fiscaux et douaniers à concéder sont repris dans une convention signée entre le Ministre chargé des Finances et l''investisseur. Ils sont corrélés au degré stratégique du projet d''investissement et constituent la contrepartie des impacts socio-économiques dudit projet au niveau communautaire ou territoriale.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('4c8fbc8a-f0ce-4181-be26-8cfa6c6b2fcb', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', '4267e79e-2454-4b6f-bba2-00d06a55fa98', 44, 'Engagements de l''investisseur au titre de l''agrément d''investissement socialement responsable', 'L''investisseur éligible à l''agrément d''investissement socialement responsable applique une politique de contenu local, notamment par la création d''emplois, le recours à la sous-traitance et le transfert de technologies et de compétences.
INSERT INTO public.code_articles (id, chapitre_id, section_id, numero, titre, contenu, created_at, updated_at) VALUES ('af4ae55f-57fc-4f35-b630-81b51698e257', '6e0ffcf6-81f2-4ec3-b1b2-65a8ac70d111', '4267e79e-2454-4b6f-bba2-00d06a55fa98', 43, 'Procédure d''attribution de l''agrément d''investissement socialement responsable', 'La demande d''attribution de l''agrément d''investissement socialement responsable (ISR) est adressée par l''investisseur au Ministre chargé des Finances, par l''entremise de l''organe en charge de la promotion des investissements.
